import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const [stats, setStats] = useState({ totalBookings: 0, activeBookings: 0, totalSlots: 0, revenue: 0, totalUsers: 0 });
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchAdminData = async () => {
      try {
        const role = localStorage.getItem("role");
        if (role !== "admin") {
          navigate("/");
          return;
        }

        const statsRes = await axios.get("/admin/stats");
        setStats(statsRes.data);

        const bookingsRes = await axios.get("/admin/bookings");
        setBookings(bookingsRes.data);

        setLoading(false);
      } catch (err) {
        console.error("Admin Access Error", err);
        navigate("/");
      }
    };
    fetchAdminData();
  }, [navigate]);

  if (loading) return <div style={{ textAlign: "center", marginTop: "50px" }}>Loading Admin Dashboard...</div>;

  return (
    <div style={{ padding: "40px", maxWidth: "1200px", margin: "0 auto" }}>
      <h1 style={{ color: "#2c3e50", borderBottom: "2px solid #eee", paddingBottom: "10px" }}>Admin Dashboard 🛡️</h1>

      {/* Stats Grid */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: "20px", marginTop: "30px" }}>
        <StatCard title="Total Users" value={stats.totalUsers} icon="👥" color="#3498db" />
        <StatCard title="Active Bookings" value={stats.activeBookings} icon="🚗" color="#2ecc71" />
        <StatCard title="Total Slots" value={stats.totalSlots} icon="🅿️" color="#f1c40f" />
        <StatCard title="Total Revenue" value={`$${stats.revenue}`} icon="💰" color="#e74c3c" />
      </div>

      {/* Bookings Table */}
      <h2 style={{ marginTop: "50px", color: "#34495e" }}>Recent Bookings</h2>
      <div style={{ overflowX: "auto", background: "white", borderRadius: "10px", boxShadow: "0 4px 10px rgba(0,0,0,0.05)" }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "#f8f9fa", textAlign: "left" }}>
              <th style={thStyle}>User</th>
              <th style={thStyle}>Vehicle</th>
              <th style={thStyle}>Location</th>
              <th style={thStyle}>Slot</th>
              <th style={thStyle}>Time</th>
              <th style={thStyle}>Status</th>
            </tr>
          </thead>
          <tbody>
            {bookings.map(b => (
              <tr key={b._id} style={{ borderBottom: "1px solid #eee" }}>
                <td style={tdStyle}>
                  <div>{b.userId?.name || "Unknown"}</div>
                  <div style={{ fontSize: "0.8em", color: "#888" }}>{b.userId?.email}</div>
                </td>
                <td style={tdStyle}>{b.vehicleNumber || "N/A"}</td>
                <td style={tdStyle}>{b.slotId?.parkingLotId?.name || "Unknown"}</td>
                <td style={tdStyle}>{b.slotId?.slotNumber || "N/A"}</td>
                <td style={tdStyle}>
                  <div>{new Date(b.startTime).toLocaleDateString()}</div>
                  <div style={{ fontSize: "0.8em", color: "#888" }}>{new Date(b.startTime).toLocaleTimeString()} - {new Date(b.endTime).toLocaleTimeString()}</div>
                </td>
                <td style={tdStyle}>
                  <span style={{
                    padding: "5px 10px", borderRadius: "15px", fontSize: "0.8em",
                    background: b.status === "Booked" ? "#e8f5e9" : "#ffebee",
                    color: b.status === "Booked" ? "#2e7d32" : "#c62828"
                  }}>
                    {b.status}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const StatCard = ({ title, value, icon, color }) => (
  <div style={{ background: "white", padding: "20px", borderRadius: "10px", boxShadow: "0 4px 10px rgba(0,0,0,0.05)", borderLeft: `5px solid ${color}` }}>
    <div style={{ fontSize: "2em", float: "right" }}>{icon}</div>
    <div style={{ color: "#7f8c8d", fontSize: "0.9em" }}>{title}</div>
    <div style={{ fontSize: "1.8em", fontWeight: "bold", color: "#2c3e50" }}>{value}</div>
  </div>
);

const thStyle = { padding: "15px", color: "#7f8c8d", fontSize: "0.9em", textTransform: "uppercase" };
const tdStyle = { padding: "15px", color: "#2c3e50" };
